#!/usr/bin/env node
// convert-pipeobjs.mjs -- extract the Lightwave (LWO) factory models from
// xscreensaver-6.15/hacks/glx/pipeobjs.c into a verbatim JS data module
// (hacks/pipeobjs.js). Generated; do not edit pipeobjs.js by hand.
//
// pipeobjs.c was itself machine-generated ("by lw2ogl") and holds, per model,
// three flat C arrays -- <Name>_PNTS (GLfloat xyz), <Name>_normals (GLfloat
// per-polygon face normals) and <Name>_POLS (unsigned short polygon stream) --
// plus a `struct lwo LWO_<Name>` giving num_pnts. We copy the numeric tokens
// VERBATIM (as source strings, no reformatting) so the data is byte-faithful;
// hacks/lwo.js's buildLWO() is the JS port of buildlwo.c that interprets it.

import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const SRC = join(here, '..', 'xscreensaver-6.15', 'hacks', 'glx', 'pipeobjs.c');
const OUT = join(here, '..', 'hacks', 'pipeobjs.js');

// The 9 models, in pipes.c's declaration order. Names match the C `LWO_<Name>`
// (so e.g. C's LWO_BigValve -> export const BigValve).
const NAMES = [
  'BigValve', 'Bolts3D', 'GuageConnector', 'GuageDial', 'GuageFace',
  'GuageHead', 'PipeBetweenBolts', 'ElbowBolts', 'ElbowCoins',
];

const src = readFileSync(SRC, 'utf8');

// pull the body between `<id> = {` and the next `}` (the arrays have no nested
// braces). Returns the verbatim token list (strings) split on commas/whitespace.
function arrayTokens(id) {
  const re = new RegExp(id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*\\[\\]\\s*=\\s*\\{([^}]*)\\}');
  const m = src.match(re);
  if (!m) throw new Error('array not found: ' + id);
  return m[1]
    .split(/[\s,]+/)
    .filter((t) => t.length > 0);
}

function numPnts(name) {
  const re = new RegExp('struct\\s+lwo\\s+LWO_' + name + '\\s*=\\s*\\{\\s*([0-9]+)');
  const m = src.match(re);
  if (!m) throw new Error('struct not found: LWO_' + name);
  return parseInt(m[1], 10);
}

let body = '';
const stats = [];
for (const name of NAMES) {
  const pnts = arrayTokens(name + '_PNTS');
  const normals = arrayTokens(name + '_normals');
  const pols = arrayTokens(name + '_POLS');
  const n = numPnts(name);

  if (pnts.length !== n * 3) {
    throw new Error(`${name}: PNTS has ${pnts.length} floats, expected num_pnts*3 = ${n * 3}`);
  }
  if (normals.length % 3 !== 0) {
    throw new Error(`${name}: normals length ${normals.length} not a multiple of 3`);
  }
  const polsNum = pols.map((t) => parseInt(t, 10));
  if (polsNum[polsNum.length - 1] !== 0) {
    throw new Error(`${name}: POLS not 0-terminated`);
  }

  // count polygons (and triangles after fan) via the real state machine.
  let pp = 0, np = 0, polys = 0, tris = 0;
  for (;;) {
    if (np <= 0) {
      np = polsNum[pp] + 2;
      if (np < 3) break;
      if (np >= 5) { polys++; tris += (np - 2) - 2; }
    } else if (np === 1) { /* end */ } else { /* vertex */ }
    np--; pp++;
  }
  stats.push({ name, points: n, faceNormals: normals.length / 3, polys, tris });

  const wrap = (arr) => {
    // 12 tokens per line, indented, verbatim source strings.
    const lines = [];
    for (let i = 0; i < arr.length; i += 12) lines.push('    ' + arr.slice(i, i + 12).join(', '));
    return lines.join(',\n');
  };

  body += `export const ${name} = {\n`;
  body += `  num_pnts: ${n},\n`;
  body += `  pnts: [\n${wrap(pnts)},\n  ],\n`;
  body += `  normals: [\n${wrap(normals)},\n  ],\n`;
  body += `  pols: [\n${wrap(pols)},\n  ],\n`;
  body += `};\n\n`;
}

const header = `// pipeobjs.js -- GENERATED by tools/convert-pipeobjs.mjs from
// xscreensaver-6.15/hacks/glx/pipeobjs.c. Do not edit by hand; re-run the tool.
//
// The Lightwave (LWO) models for the "factory" gadgetry in pipes -- valves,
// gauges, bolt flanges -- copied VERBATIM (original numeric tokens) from the
// machine-generated C. Each model has: num_pnts, pnts (xyz triples), normals
// (one face normal per polygon, in polygon order) and pols (the unsigned-short
// polygon stream: [K, idx0..idx_{K-1}, surface#] records, 0-terminated).
// hacks/lwo.js's buildLWO() interprets these exactly as hacks/glx/buildlwo.c does.

`;

writeFileSync(OUT, header + body);

console.log('wrote', OUT);
console.table(stats);
const tot = stats.reduce((a, s) => ({ points: a.points + s.points, polys: a.polys + s.polys, tris: a.tris + s.tris }), { points: 0, polys: 0, tris: 0 });
console.log('totals:', tot);
